parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "narration": {
      "type": "string",
      "description": "The full spoken narration script (60-90 words, conversational)"
    },
    "scene1_prompt": {
      "type": "string",
      "description": "FLUX image prompt for scene 1 (cinematic, detailed, no text)"
    },
    "scene2_prompt": {
      "type": "string",
      "description": "FLUX image prompt for scene 2 (cinematic, detailed, no text)"
    },
    "scene3_prompt": {
      "type": "string",
      "description": "FLUX image prompt for scene 3 (cinematic, detailed, no text)"
    },
    "videoTitle": {
      "type": "string",
      "description": "YouTube title (max 60 chars, curiosity-driven)"
    },
    "description": {
      "type": "string",
      "description": "2-sentence YouTube description + 1 call to action"
    },
    "tags": {
      "type": "string",
      "description": "5 comma-separated hashtags"
    }
  },
  "required": ["narration", "scene1_prompt", "scene2_prompt", "scene3_prompt", "videoTitle", "description", "tags"]
}

parameters.body:
={
  "prompt": {
    "1": {
      "class_type": "CheckpointLoaderSimple",
      "inputs": {
        "ckpt_name": "flux1-dev.safetensors"
      }
    },
    "2": {
      "class_type": "CLIPTextEncode",
      "inputs": {
        "text": {{ JSON.stringify($json.output.scene1_prompt) }},
        "clip": ["1", 1]
      }
    },
    "3": {
      "class_type": "CLIPTextEncode",
      "inputs": {
        "text": "blurry, low quality, text, watermark, ugly, deformed",
        "clip": ["1", 1]
      }
    },
    "4": {
      "class_type": "EmptyLatentImage",
      "inputs": {
        "width": 576,
        "height": 1024,
        "batch_size": 1
      }
    },
    "5": {
      "class_type": "KSampler",
      "inputs": {
        "seed": {{ Math.floor(Math.random() * 1000000) }},
        "steps": 20,
        "cfg": 7,
        "sampler_name": "euler",
        "scheduler": "normal",
        "denoise": 1,
        "model": ["1", 0],
        "positive": ["2", 0],
        "negative": ["3", 0],
        "latent_image": ["4", 0]
      }
    },
    "6": {
      "class_type": "VAEDecode",
      "inputs": {
        "samples": ["5", 0],
        "vae": ["1", 2]
      }
    },
    "7": {
      "class_type": "SaveImage",
      "inputs": {
        "filename_prefix": "scene1",
        "images": ["6", 0]
      }
    }
  },
  "client_id": "n8n-workflow"
}

